var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"갑자기 왜 일어나나. 술잔은 아직 가득 차 있는데.","JPN":"急にどこに行くんだ。グラスにはまだ酒が残っているぞ。","ENG":"Getting up so soon? Your glass is still full.","TWN":"怎麼突然站起來了。酒杯還沒空呢。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"......윌버. 당장 그 망할 놈을 찾으러 가야겠어.","JPN":"……ウィルバー。今すぐあのクソ野郎を見つけ出さないと。","ENG":"... Wilbur. I need to find that bastard right now.","TWN":"……韋爾伯。我要立刻去找那個該死的傢伙。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"앉게.","JPN":"座ってくれ。","ENG":"Have a seat.","TWN":"坐下。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"술자리는 이제 끝났어. 네가 왔던 곳으로 돌아가기나 해.","JPN":"おしゃべりはもう終わりだ。お前は元の場所に戻れ。","ENG":"Party's over. Just go back to where you came from.","TWN":"不喝了，你從哪來回哪去吧。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"이건 술친구로서 하는 충고야.","JPN":"これは飲み友達としての忠告だ。","ENG":"This is just a friendly tip from your drinking buddy.","TWN":"這是作為酒友的忠告。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"앉게. 어서. 술자리는 아직 시작도 안 했어.","JPN":"座ってくれ。まだ話の途中だ。","ENG":"Have a seat. Now. We're only getting started.","TWN":"坐下。快，酒局還沒開始呢。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네는 매번 이 무렵에 마음대로 자리를 떠났지.","JPN":"君は毎回このタイミングで勝手に席を離れてしまう。","ENG":"You'd always get up around this point.","TWN":"你每次都是這個時候隨意離開。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하지만 이번만큼은 곤란해.","JPN":"だが今回だけは困る。","ENG":"But I can't have you doing that this time.","TWN":"但這次可不行。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"너...... 이제 보니 사람 깔보는 태도가 그 하얀 그림자와 비슷하군.","JPN":"お前……その人に対するナメた態度はあの白いシャドウに似ているな。","ENG":"Hang on... Come to think of it, you sound a lot like that pale Shadow, being all condescending.","TWN":"你……現在看來，你這傲慢的態度跟那個小白暗影很像啊。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"......그러고 보니 더 수상해.","JPN":"……よく考えたら怪しいな。","ENG":"I just noticed this entire situation is super fishy...","TWN":"……如此說來，更奇怪了。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"왜 내가 여기서 끝도 없이 뭔가를 기다리고 있는 거지?","JPN":"なぜ私はここで何かをずっと待っているんだ？","ENG":"What am I waiting here for, exactly?","TWN":"為什麼我一直在這裡等待呢，我在等什麼？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"애초에 여긴 대체 어디야! 설마 너도 그년이랑 한통속이냐?!","JPN":"そもそもここはどこだ！　まさかお前もあの女とグルか！？","ENG":"Where the hell am I, even?! Are you working with that albino punk?!","TWN":"這裡到底是哪！難道你也跟她是一夥的？！"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_THUD"},{"id":"L17_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"두려워하는 심정은 나도 이해하네, 리타 아르세니코.","JPN":"恐れる気持ちは理解している、リタ・アルセニコ。","ENG":"I understand why you'd be afraid, Rita Arsenico.","TWN":"我理解你的恐懼，麗塔·阿塞妮克。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"두려워해? 내가?","JPN":"恐れるだと？　私が？","ENG":"Afraid? Me?","TWN":"恐懼？我嗎？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그래. 자네는 진실을 마주하기 두려워하고 있어.","JPN":"そう。君は真実と向き合うことを恐れている。","ENG":"That’s right. You're afraid to face the truth.","TWN":"是啊，你害怕面對真相。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"늘 그랬겠지. 진실을 마주하지 않아야 견딜 수 있었을 테니까.","JPN":"いつもそうして耐えてきたんだろう。真実から目を逸らすことで。","ENG":"Like you always have been. Avoiding the truth is the only way you can bear to go on living.","TWN":"你應該一直如此吧。因為只有不面對真相，你才能堅持下去。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네는 범죄자로 살아가기엔 너무 섬세한 사람이거든.","JPN":"君は犯罪者として生きるには、繊細すぎる人なんだよ。","ENG":"Your personality is far too delicate for the criminal life.","TWN":"你性格太過細膩，無法以罪人的身份活著。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하지만 그렇다고 언제까지 아무도 없는 술집에 혼자 있을 셈인가?","JPN":"とはいえ、いつまで誰もいないバーで一人居続けるつもりだ？","ENG":"Even so, how long do you think you can just sit in this abandoned bar by yourself?","TWN":"不過，你要在無人的酒館獨自待到什麼時候？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"손님도, 바텐더가 없어도 참을 수 있어.","JPN":"客も、バーテンダーがいなくても我慢できる。","ENG":"Sure, maybe you can get over the lack of customers, or even the bartender.","TWN":"沒有顧客，沒有吧台，也能忍受。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"멋진 음악은...... 조금 아쉽긴 하군.","JPN":"音楽がないのは……ちょっと寂しいが。","ENG":"As for the lack of music... Well, that is a bit disappointing.","TWN":"美好的音樂……有點可惜。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하지만 기약 없는 기다림은 다른 얘기일세.","JPN":"しかし、約束のない待ち合わせはまた別の話だ。","ENG":"However, it's an entirely different story to be waiting with no end.","TWN":"但遙遙無期的等待卻是另外一回事。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그건 참을 수도 없고, 참아서도 안 돼.","JPN":"それは我慢できるものではないし、我慢してはならない。","ENG":"It's unbearable. I wouldn't wish it on my worst enemy.","TWN":"那不能忍受，也不應該忍受。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"서로한테 더 깊은 상처만 줄 뿐이지.","JPN":"互いにより深い傷を負うだけだ。","ENG":"It'll only cause even more heartache.","TWN":"因為不過是彼此徒增傷害罷了。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"무슨 헛소리인지 모르겠군. 게다가 알고 싶지도 않아.","JPN":"何を言っているかさっぱりわからないな。知りたくもないけど。","ENG":"I have no idea what you're rambling on about. And I don't want to find out.","TWN":"不知道你在胡說八道些什麼，也不想知道。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"말해. 왜 나한테 접근했는지.","JPN":"正直に話せ。なぜ私に近づいてきた。","ENG":"Tell me. Why did you approach me?","TWN":"說吧，為什麼接近我。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네들의 기약 없는 기다림을 끝내 주러 왔다네.","JPN":"君たちのいつ会えるかわからない約束を果たしてあげるために来たのさ。","ENG":"I came to put an end to your endless waiting.","TWN":"我是來結束你遙遙無期的等待的。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"그렇게 대답한다면 나도 더 이상 할 얘기는 없어.","JPN":"それが答えなら、私もこれ以上話すことはない。","ENG":"If you're going to give me that crap, then I've got nothing further to say.","TWN":"既然如此，我也沒什麼好說的了。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"내가 누굴 기다리고 있다고?","JPN":"私が誰かを待っていると？","ENG":"You think I'm waiting for someone?","TWN":"你說我在等人？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"정말 그렇게 생각한다면 큰 착각이라고 해 주지.","JPN":"本気でそう思っているならえらい勘違いだな。","ENG":"You're sorely mistaken if that's what you think.","TWN":"如果你真那麼想，那我只能說你大錯特錯了。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"이 술집에서 날 찾던 연놈들 중에 반가워할 만한 얼굴은 한 명도 없었어.","JPN":"このバーで私を探していた連中の中で、会えたからって喜びそうな人なんていないんだよ。","ENG":"Nobody who'd be looking for me at this bar would be glad to see me.","TWN":"到這家酒館裡找我的傢伙中，沒有一個是讓我喜歡的。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"글쎄. 방금 전에 그 아이에게 자기 입으로 말했다고 털어놓지 않았나.","JPN":"さあどうかな。さっきあの子に自分の口で言っただろう。","ENG":"I don't know. Didn't you just say you made a promise to the girl?","TWN":"是嗎，剛才不是你親口對那個孩子說的嗎。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"생일이 지나면 같이 오자고.","JPN":"誕生日が過ぎたら一緒に来ようと。","ENG":"That you'd come here for her birthday?","TWN":"過了生日，就一起來。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"......꼬맹이?","JPN":"……ガキ？","ENG":"The kid?","TWN":"……小鬼？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"나는 자네를 도울 준비가 되어 있어.","JPN":"私は君を手助けする準備ができている。","ENG":"I'm prepared to help you.","TWN":"我隨時可以幫你。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네가 도움을 받을 준비가 됐다는 가정 하에 말이네만.","JPN":"君が助けを受ける準備ができているという前提になるが。","ENG":"But only when you're prepared to let me help you.","TWN":"在你已經做好要接受幫助的前提下。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"가슴 속에 오래 고여 있던 이야기를 털어놓기는 무척 힘들겠지.","JPN":"長い間胸に納めていた話を打ち明けるのはきっと辛いことだろう。","ENG":"It must be hard to share all the things that have festered within for so long.","TWN":"要說出心中埋藏許久的故事是很困難的。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하지만 다행히 여기에는 좋은 술이 있고......","JPN":"しかし、幸いここには上質な酒があって……","ENG":"But lucky for you, we've got some fine drinks here...","TWN":"但幸好這裡有好酒……"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_03"},{"id":"L48_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이야기를 들어 줄 상대까지 있군.","JPN":"話を聞いてくれる相手もいる。","ENG":"And someone to lend you their ear.","TWN":"還有傾聽你故事的對象。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"나는......","JPN":"私は……","ENG":"I...","TWN":"我……"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"지켜 주고 싶었어<color=#808080>요</color>.","JPN":"守ってあげたかった<color=#808080>のです。</color>","ENG":"...wanted to protect... <color=#808080>Rita.</color>","TWN":"想守護<color=#808080>她</color>。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};